import java.util.*;
public class ValidateRange {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int value = -1;
        while (value < 1 || value > 10) {
            System.out.print("Enter an integer 1..10: ");
            if (sc.hasNextInt()) {
                value = sc.nextInt();
            } else {
                sc.next(); // consume invalid token
            }
        }
        System.out.println("You entered: " + value);
        sc.close();
    }
}

import java.util.*;
public class SentinelSum {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int sum = 0;
        System.out.print("Enter numbers (-1 to end): ");
        int n = sc.nextInt();
        while (n != -1) {
            sum += n;
            n = sc.nextInt();
        }
        System.out.println("Total = " + sum);
        sc.close();
    }
}

public class MultTable {
    public static void main(String[] args) {
        int R = 5, C = 5;
        for (int r = 1; r <= R; r++) {
            for (int c = 1; c <= C; c++) {
                System.out.printf("%4d", r * c);
            }
            System.out.println();
        }
    }
}
